events.text:
@font-face {
  font-family: "GRADE-quality";
  src: url();
  src: url('https://gradepro.org/fonts/GRADE-quality.eot');
  src: url('https://gradepro.org/fonts/GRADE-quality.eot?#iefix')
      format('embedded-opentype'),
    url('https://gradepro.org/fonts/GRADE-quality.woff') format('woff'),
    url('https://gradepro.org/fonts/GRADE-quality.ttf') format('truetype'),
    url('https://gradepro.org/fonts/GRADE-quality.svg#GRADE-quality')
      format('svg');
  font-weight: normal;
  font-style: normal;
}

@media print {
  @page {
    size: portrait;




  }
}

body {
  -webkit-print-color-adjust:exact;
  font-size: 8pt;
  font-family: Calibri, Verdana , 'Arial Narrow', Arial, sans-serif;
  font-stretch: condensed;
  color: black;
  padding: 5px;
  margin:0;
}

figure {
  margin: 0;
}

h1 {
  font-family: Calibri, Verdana , 'Arial Narrow', Arial, sans-serif;
  font-size: 15pt;
  margin-bottom: 1pt;
  text-transform: uppercase;
}

h2 {
  font-family: Calibri, Verdana , 'Arial Narrow', Arial, sans-serif;
  font-size: 13pt;
}

p {
  margin: 0;
}

thead, tfoot { display: table-row-group }

table {
  width: 100%;
  border-collapse: collapse;
}

td {
  vertical-align: top;
  padding: 5px;
}

fieldset {
  border: none;
}

.alignment--left {
  text-align: left;
}

.alignment--center {
  text-align: center;
}

.alignment--right {
  text-align: right;
}

.recommendations-header {
  position: relative;
}

.recommendations-header table {
  width: 100%;
}

.recommendations-header td {
  border-bottom: 1px solid #2E74B5;
}

.recommendations-header tr.title h1 {
  margin-bottom: 1pt;
}

.recommendations-header tr.title td {
  padding: 0;
}

.recommendations-header .question {
  background-color: #2E74B5;
  border-right: 1px solid #2E74B5;
  color: #ffffff;
  font-weight: bold;
  font-size: 12pt;
}

.recommendations-header td.label-cell {
  font-weight: bold;
  width: 75pt;
  background-color: #2E74B5;
  text-transform: uppercase;
  color: #ffffff;
}

.recommendations-header td.label-cell.second-col {
  background-color: #2E74B5;
}
.recommendations-header td.editable-cell {
  line-height: 10pt;
  border-right: 1px solid #2E74B5;
  width: 600pt;
}

.recommendations-header table,
.judgement-table,
.summary-of-judgements,
.recommendation-table-static,
.type-of-recommendation-table-static,
.votes-summary table {
  font-size: 8pt;
  font-family: Calibri, Verdana , 'Arial Narrow', Arial, sans-serif;
}

.recommendations-header table,
.judgement-table,
.summary-of-judgements,
.conclusions-options {
  mso-table-layout-alt: fixed;
  border-collapse: collapse;
}

.assessment-section__header {
  background-color: #2E74B5;
  color: #ffffff;
}

.assessment-section__header h2 {
  margin: 0;
}

.section-parts-title-row td {
  padding: 5px;
  text-transform: uppercase;
}

.section-parts-title-row h2 {
  margin: 0;
  font-size: 8pt;
}

.ep-section-row hr {
  border: 0;
}

.research-evidence-relative-importance,
.outcomes-table,
.research-evidence-sof {
  font-size: 7pt;
  font-family: Calibri, Verdana , 'Arial Narrow', Arial, sans-serif;
}

.judgement-table td,
.summary-of-judgements td {
  border: 1px solid black;
}

.judgement-table .judgement-list {
  margin-top: 15px;
}

.judgement-table .judgement-list label{
  margin-bottom: 10px;
  display: block;
}

tr.headers,
.research-evidence-sof th,
.research-evidence-relative-importance th {
  background: #9bbde0;
  line-height: 13pt;
}

.headers td.blank,
.diagnostic-headers th.blank {
  width: 20px;
  border-right: none;
  background: white;
  border: none;
}

.headers td {
  vertical-align: middle;
  text-align: center;
  text-transform: uppercase;
  font-weight: bold;
}

td.criteria-cell {
  width: 155px;
}

td.judgement {
  width: 160pt;
}

td.additional-considerations {
  width: 220pt;
}

.resources_required > td,
.undesirable_effects > td,
.certainty_of_evidence > td,
.balance_of_effects > td,
.cost_effectiveness > td {
  height: 160px;
}

.certainty_of_evidence_of_required_resources > td {
  height: 200px
}

.summary-of-judgements {
  border-collapse: collapse;
}

.summary-of-judgements .header .summary {
  font-size: 14pt;
  text-align: center;
  background-color: #2E74B5;
  color: #ffffff;
}

.summary-of-judgements-header {
  page-break-inside: avoid;
}

.summary-of-judgements-header h2 {
  font-weight: bold;
}

.summary-of-judgements th {
  padding: 5px;
  border: 1px solid black;
  line-height: 13pt;
  font-weight: bold;
  text-transform: uppercase;
}

.summary-of-judgements th.blank {
  border: none;
}

.summary-of-judgements .section-name {
  background-color: #2E74B5;
  color: #ffffff;
  width: 134pt;
  padding-left: 5px;
  line-height: 13pt;
  font-weight: bold;
  vertical-align: middle;
  text-transform: uppercase;
  text-align: center;
}

.summary-of-judgements .options-container {
  width: auto;
  position: relative;
  padding: 0;
}

.summary-of-judgements .option-text {
  box-sizing: border-box;
  width: 130px;
  height: 100%;
  border-right: 1px solid black;
  vertical-align: middle;
  text-align: center;
  color: rgb(174,170,170);
}

.summary-of-judgements .option-text.checked {
  font-weight: bold;
  color: #000;
}

.summary-of-judgements .option-text.empty {
  background-color: #dfdfdf;
}

.recommendation-section {
  page-break-before: always;
}

.recommendation-table-static {
  border-collapse: collapse;
}

.conclusions-header h2 {
  margin: 0;
  padding: 5px;
  border-top: 1px solid black;
  border-left: 1px solid black;
  border-right: 1px solid black;
}

.recommendation-table-static td {
  padding: 0;
}

.recommendation-table-static .conclusions-section-title,
.recommendation-table-static .recommendation-section-title {
  padding: 5px;
  background-color: #2E74B5;
  color: #ffffff;
}

.recommendation-table-static .related-recommendation {
  margin: 10px 5px;
}

.recommendation-table-static .conclusions-section-title h2,
.recommendation-table-static .recommendation-section-title h2 {
  margin: 0;
}

.recommendation-table-static .content {
  padding: 5px;
}

.recommendation-table-static .title-row td,
.recommendation-table-static .filled {
  background-color: #AAD6D2;
  width: 200pt
}

.recommendation-table-static td.filled {
  font-weight: bold;
  text-transform: uppercase;
}

.recommendation-types fieldset {
  padding: 0;
  margin: 0;
}

.recommendation-types .conclusions-options td.selected {
  background-color: #2E74B5;
  font-weight: bold;
  color: #ffffff;
}

.conclusions-options td {
  text-align: center;
  position: relative;
  padding: 0;
  color: #000000;
}

.conclusions-options .option-labels td {
  border-left: 1px solid #000000;
  border-right: 1px solid #000000;
  border-top: 1px solid #000000;
  padding-top: 5px;
  font-size: 8pt;
  font-family: Calibri, Verdana , 'Arial Narrow', Arial, sans-serif;
}

.conclusions-options .option-marks td {
  border-left: 1px solid #000000;
  border-right: 1px solid #000000;
  border-bottom: 1px solid #000000;
  padding-bottom: 5px;
}

/* VOTING */

.voting-title,
.spacer {
  background: #9bbde0;
  font-weight: bold;
  text-transform: uppercase;
  text-align: center;
}

.voting-details .voted-data {
  text-align: center;
}

.voting-details .vote-option-text {
  width: 80%;
  border: 0;
  text-align: left;
}

.voting-details .votes-ratio {
  width: 20%;
  border: 0;
  text-align: right;
}

.voting-judgment-cell hr {
  margin: 1px;
}

.voting-judgment-cell .draft-judgement {
  margin-bottom: 10px;
}

.voting-details .voting-details__comments,
.voting-details .voting-details__judgement {
  padding: 10px;
  border: 1px solid #000;
}

.question-text {
  font-size: 13pt;
  font-weight: bold;
}

.recommendation-types {
  margin-bottom: 50px;
}

.conclusions-options {
  position: relative;
  table-layout: fixed;
  border-collapse: collapse;
}

.conclusions-options td {
  width: 20%;
}

.conclusions-section .voting-title {
  height: 20px;
  background: #AAD6D2;
}

.conclusions-section td.content {
  height: 54pt;
}
.recommendation-table-static .voting-details__judgement,
.conclusions-voting-details .voting-judgment-cell {
  width: 20%;
}

.recommendation-table-static .voting-details__comments,
.conclusions-voting-details .voting-comments-cell {
  width: 80%;
}

.votes-summary div {
  position: relative;
}

.votes-summary div .filler {
  background-color: #c9dac2;
  opacity: 0.5;
  -ms-filter: "progid:DXImageTransform.Microsoft.Alpha(Opacity=50)";
  filter: alpha(opacity=50);
  height: 100%;
  position: absolute;
  top: 0px;
}

.team-comments,
.admin-comment {
  margin-top: 20px;
}

.comments-label {
  text-transform: uppercase;
}

.member-name {
  font-weight: bold;
}

.comment {
  margin-top: 5px
}

.comment p {
  margin: 0;
}

.spacer {
  height: 20px;
}

.spacer td {
  border: none;
}

.spacer .left {
  border-left: 1px solid black;
}

.spacer .right {
  border-right: 1px solid black;
}

/* Panel voice v2 */

.panel-voice-results td {
  padding: 5px;
  border: 1px solid black;
}

.conclusions-section .panel-voice-results .ep-cell,
.recommendation-section .panel-voice-results .ep-cell {
  width: 20%;
}

.conclusions-section .panel-voice-results .responses-details-cell,
.recommendation-section .panel-voice-results .responses-details-cell {
  width: 80%;
}

.panel-voice-results .responses-details-cell .responses-details .title {
  margin-top: 55px;
}

.panel-voice-results .judgement-details .voted-data,
.panel-voice-results .responses-details-cell .responses-details .title,
.panel-voice-results .responses-details-cell .responses-details .admin-comment-caption {
  font-weight: bold;
  margin-bottom: 10px;
}

.panel-voice-results .responses-details-cell .responses-details .responses-group {
  margin-bottom: 10px;
}
.panel-voice-results .responses-details-cell .responses-details .responses-group .option-name {
  margin-bottom: 5px;
}

.panel-voice-etd .spacer td {
  border-left: 1px solid black;
  border-right: 1px solid black;
}

.panel-voice-details {
  display: table;
  width: 100%;
}

.panel-voice-details .draft-judgement {
  font-weight: bold;
  margin-bottom: 5px;
}

.panel-voice-details .criteria-judgement-cell {
  width: 30%;
}

.panel-voice-details .judgement-details {
  display: table-cell;
  width: calc(30vw);
  padding-right: 10px;
}

.panel-voice-details .responses-details {
  display: table-cell;
  vertical-align: top;
  padding-left: 10px;
}

.panel-voice-details .voted-data {
  text-align: left;
}


/* INSERTED TABLES */

table.short tr.outcome-diag-sof-row th {
  padding: 5px;
  background-color: #275c99;
  border-color: #000;
  color: #fff;
  text-align: center;
  vertical-align: middle;
}
table.short tr.outcome-diag-sof-row th.effect-head-cell {
  background-color: #95b3d7;
  color: #000;
}
table.short tr.outcome-diag-sof-row th.prevalence-1,
table.short tr.outcome-diag-sof-row th.prevalence-2,
table.short tr.outcome-diag-sof-row th.prevalence-3 {
  background-color: #b8cce4;
  font-weight: normal;
  color: #000;
}
table.short tr.outcome-diag-sof-row td.quality,
table.short tr.outcome-diag-sof-row td.no-of-participants-studies {
  border-left: 1px solid #000;
  text-align: center;
  background: none;
}
table.short thead > tr {
  background-color: #fff;
  color: #000;
}
table.short thead > tr th {
  padding: 5px;
  vertical-align: top;
  font-weight: bold;
}
table.short tbody {
  border-bottom: solid 2px #000;
}
table.short tbody td {
  text-align: left;
  vertical-align: top;
  border-top: solid 1px #000;
  border-bottom: solid 1px #000;
  border-left: none;
  border-right: none;
  word-wrap: break-word;
}
table.short tbody td.diagnostic-outcome-label,
table.short tbody td.diagnostic-outcome-label.active {
  vertical-align: middle;
  text-align: left;
  background: none !important;
}
table.short tbody td.diagnostic-effect {
  background-color: #dbe5f1;
  border-right: 1px solid #000;
  vertical-align: middle;
}
table.short tbody td.complications-prevalences-desc,
table.short tbody td.inconclusive-prevalences-desc {
  background-color: #dbe5f1;
}
table.short tbody td.control-label {
  background-color: #e0e0e0;
  border-color: #000;
  font-weight: bold;
}
table.short tbody td.corresponding-risk {
  background-color: #ebebeb;
}
table.short tbody td.risk-with-control {
  background-color: none;
}
table.short tbody td.risk-difference-with-intervention {
  background-color: #ededed;
}
table.short .printout {
  border-top: solid 2px #000;
  border-bottom: solid 2px #000;
  border-left: none;
  border-right: none;
}

table.short .blue-cell {
  text-align: left;
  color: #fff;
  font-weight: normal;
  background-color: #3271aa;
  border: 1px solid #efefef;
}
table.short .grey-cell {
  text-align: left;
  border-top: 1px solid #efefef;
  border-right: 1px solid #efefef;
  background-color: #e0e0e0;
}

/* IMPORTANCE RANGE */

.low {
  background-color: #fcfcfc;
}

.moderate {
  background-color: #f0f0f0;
}

.high {
  background-color: #e3e3e3;
}

.quality-sign {
  font-family: 'GRADE-quality', Cambria, Helvetica, Arial;
  font-size: 14px;
}

div.references-summary h1 {
  page-break-before: always !important;
}

/* APPENDICES */
div.appendices h1 {
  page-break-before: always !important;
}

p.appendix-title,
p.appendix-title-first {
  margin-top: 16px;
  font-size: 1.3em;
}

p.appendix-title {
  page-break-before: always !important;
}
